import React from 'react';
import { Navigate, Outlet, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

/**
 * ProtectedRoute
 * ──────────────
 * Props:
 *   requireAdmin  – if true, also requires role === 'admin'
 *   redirectTo    – where to redirect on failure (default: /login)
 *
 * Usage:
 *   <Route element={<ProtectedRoute />}>              ← any authenticated user
 *     <Route path="/dashboard" element={<Dashboard />} />
 *   </Route>
 *
 *   <Route element={<ProtectedRoute requireAdmin />}> ← admin only
 *     <Route path="/admin" element={<AdminPanel />} />
 *   </Route>
 */
const ProtectedRoute = ({
  requireAdmin = false,
  redirectTo = '/login',
}) => {
  const { isAuthenticated, isAdmin } = useAuth();
  const location = useLocation();

  // Not logged in → send to login, preserve the attempted URL
  if (!isAuthenticated) {
    return <Navigate to={redirectTo} state={{ from: location }} replace />;
  }

  // Logged in but not an admin while admin is required → forbidden page
  if (requireAdmin && !isAdmin) {
    return <Navigate to="/forbidden" replace />;
  }

  // All checks passed – render the nested routes
  return <Outlet />;
};

export default ProtectedRoute;
